r_tnma_book_confirm_mem_th_share_loan_ne.sql:
select sc_lon_m_loan_card.loan_contract_no , to_snumber(sc_lon_m_contract.loan_request_amount) as loan_request_amount , to_snumber(sc_lon_m_loan_card.principal_balance) as principal_balance , to_snumber(sc_lon_m_contract.period_payment_amount) as period_payment_amount
from sc_lon_m_loan_card , sc_lon_m_contract
where sc_lon_m_loan_card.loan_contract_no = sc_lon_m_contract.loan_contract_no and sc_lon_m_loan_card.principal_balance > 0 and sc_lon_m_loan_card.membership_no = {0}
